public class Person {
    protected String name;
    protected int age;

    public Person(String name, int age) {
        this.name = name;
        this.age = age;
    }

    public void introduce() {
        System.out.println("Hi, I'm " + name + ", age " + age);
    }
}

public class Student extends Person {
    private String school;

    public Student(String name, int age, String school) {
        super(name, age);
        this.school = school;
    }
}

public class Main {
    public static void main(String[] args) {
        Student s = new Student("Aman", 21, "MIT");
        s.introduce();
    }
}

public class Main {
    static class Person {
        protected String name;

        Person(String name) {
            this.name = name;
        }

        void introduce() {
            System.out.println("Hi, I'm " + name);
        }
    }

    static class Student extends Person {
        private String school;

        Student(String name, String school) {
            super(name);
            this.school = school;
        }

        @Override
        void introduce() {
            System.out.println("Hi, I'm " + name + ", studying at " + school);
        }
    }

    public static void main(String[] args) {
        Student s = new Student("Aman", "MIT");
        s.introduce();
    }
}

